const url = $vars.SUPABASE_URL;
const key = $vars.SUPABASE_KEY;
if (!url || !key) throw new Error('Set SUPABASE_URL and SUPABASE_KEY as workflow variables');

const h = { 'apikey': key, 'Authorization': `Bearer ${key}` };

const [runsRes, briefRes] = await Promise.all([
  this.helpers.httpRequest({ method: 'GET', url: `${url}/rest/v1/pipeline_runs?order=completed_at.desc&limit=1`, headers: h }),
  this.helpers.httpRequest({ method: 'GET', url: `${url}/rest/v1/weekly_briefs?order=generated_at.desc&limit=1`, headers: h })
]);

const run = Array.isArray(runsRes) && runsRes[0];
if (!run) throw new Error('No pipeline runs found. Run the main pipeline first.');
const brief = (Array.isArray(briefRes) && briefRes[0]) || null;

const themesRes = await this.helpers.httpRequest({
  method: 'GET',
  url: `${url}/rest/v1/themes?week_number=eq.${run.week_number}&year=eq.${run.year}&order=confidence_score.desc`,
  headers: h
});
const themes = Array.isArray(themesRes) ? themesRes : [];

console.log(`Fetched: ${themes.length} themes | run ${run.run_id} | brief ${brief?.brief_id || 'none'}`);
return [{ json: { run, themes, brief, week_number: run.week_number, year: run.year } }];

const { run, themes, brief, week_number, year } = $input.first().json;
const checks = [];
const pass = (name, detail) => checks.push({ name, status: 'PASS', detail });
const fail = (name, detail) => checks.push({ name, status: 'FAIL', detail });
const warn = (name, detail) => checks.push({ name, status: 'WARN', detail });

// 1 — Theme count (target: 6–8)
const tc = themes.length;
if (tc >= 6 && tc <= 8) pass('Theme Count', `${tc} themes (target: 6–8)`);
else if (tc > 0) warn('Theme Count', `${tc} themes — outside target range of 6–8`);
else fail('Theme Count', 'No themes found in Supabase for this week');

// 2 — Required fields
const missingFields = themes.filter(t => !t.title || !t.summary || !t.why_it_matters || !t.what_you_can_do);
if (missingFields.length === 0) pass('Required Fields', 'All themes have title, summary, why_it_matters, what_you_can_do');
else fail('Required Fields', `${missingFields.length} themes missing required fields: ${missingFields.map(t => t.theme_id).join(', ')}`);

// 3 — ACT/WATCH tier diversity (DB stores ACT→RISING, WATCH→EMERGING)
// Map DB values back to display tiers
const tierMap = { RISING: 'ACT', BREAKING: 'ACT', EMERGING: 'WATCH', STABLE: 'WATCH', DECLINING: 'WATCH' };
const tiers = themes.map(t => tierMap[t.signal_type] || t.signal_type);
const hasACT = tiers.includes('ACT');
const hasWATCH = tiers.includes('WATCH');
const actCount = tiers.filter(t => t === 'ACT').length;
const watchCount = tiers.filter(t => t === 'WATCH').length;
if (hasACT && hasWATCH) {
  if (actCount >= 2 && actCount <= 3 && watchCount >= 5 && watchCount <= 6) {
    pass('ACT/WATCH Tier Mix', `ACT×${actCount} / WATCH×${watchCount} (target: ACT 2–3, WATCH 5–6)`);
  } else {
    warn('ACT/WATCH Tier Mix', `ACT×${actCount} / WATCH×${watchCount} — has both tiers but outside ideal range (ACT 2–3, WATCH 5–6)`);
  }
} else if (!hasACT) {
  fail('ACT/WATCH Tier Mix', `All ${tc} themes are WATCH — no ACT themes. Brief must contain both tiers.`);
} else if (!hasWATCH) {
  fail('ACT/WATCH Tier Mix', `All ${tc} themes are ACT — no WATCH themes. Brief must contain both tiers.`);
}

// 4 — Confidence score distribution (spread must be ≥20 pts, H7)
if (themes.length > 0) {
  const scores = themes.map(t => t.confidence_score);
  const avg = Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);
  const min = Math.min(...scores);
  const max = Math.max(...scores);
  const spread = max - min;
  if (spread >= 20) pass('Confidence Spread', `spread=${spread}pts ≥20 ✅ avg=${avg} (min=${min}, max=${max})`);
  else if (spread >= 10) warn('Confidence Spread', `spread=${spread}pts — below ≥20pt target. avg=${avg} (min=${min}, max=${max})`);
  else fail('Confidence Spread', `spread=${spread}pts — critically low, all themes same score. avg=${avg}`);
}

// 4b — Confidence ceiling (no theme should exceed 95%)
if (themes.length > 0) {
  const overCap = themes.filter(t => t.confidence_score > 95);
  if (overCap.length === 0) pass('Confidence Ceiling', `All themes ≤95% — no over-confidence`);
  else fail('Confidence Ceiling', `${overCap.length} themes exceed 95% cap: ${overCap.map(t => `${t.theme_id}(${t.confidence_score}%)`).join(', ')}`);
}

// 5 — Summary sentence count (must be 4–5 sentences, H8)
const summaryFails = themes.filter(t => {
  if (!t.summary) return true;
  const sentences = t.summary.trim().split(/[.!?]+/).filter(s => s.trim().length > 5);
  return sentences.length < 4 || sentences.length > 5;
});
if (summaryFails.length === 0) pass('Summary Length', `All themes have 4–5 sentence summaries`);
else fail('Summary Length', `${summaryFails.length} themes have wrong sentence count (need 4–5): ${summaryFails.map(t => t.theme_id).join(', ')}`);

// 6 — Banned title words (Fix N + Fix P)
const bannedTitleWords = [
  'revolution', 'expanding', 'evolution', 'rise of', 'adoption of', 'advances in',
  'advancements in', 'new era', 'transformation', 'future of', 'landscape', 'growing',
  'surge', 'wave', 'boom', 'overview', 'latest', 'emergence', 'emergence of',
  'update', 'updates', 'progress', 'developments', 'trends', 'solutions',
  'opportunities', 'challenges', 'impact', 'implications'
];
const bannedTitleThemes = themes.filter(t => {
  const lower = (t.title || '').toLowerCase();
  return bannedTitleWords.some(w => lower.includes(w));
});
if (bannedTitleThemes.length === 0) pass('Title Specificity', 'No banned vague title words detected');
else fail('Title Specificity', `${bannedTitleThemes.length} themes have banned title words: ${bannedTitleThemes.map(t => `"${t.title}"`).join(', ')}`);

// 7 — Citation coverage
const noCitations = themes.filter(t => !t.citations || t.citations.length === 0);
if (noCitations.length === 0) pass('Citation Coverage', `All ${tc} themes have at least 1 citation`);
else fail('Citation Coverage', `${noCitations.length} themes have no citations: ${noCitations.map(t => t.theme_id).join(', ')}`);

// 8 — Citation URL format
const badUrls = themes.flatMap(t => (t.citations || []).filter(c => !c.url || !c.url.startsWith('http')));
if (badUrls.length === 0) pass('Citation URL Format', 'All citation URLs start with http');
else fail('Citation URL Format', `${badUrls.length} citations have missing or invalid URLs`);

// 9 — Signal ID format (hallucination check)
const allIds = themes.flatMap(t => t.supporting_signal_ids || []);
const badIds = allIds.filter(id => !String(id).startsWith('tv-') && !String(id).startsWith('gh-'));
if (badIds.length === 0) pass('Signal ID Format', `${allIds.length} IDs all match tv-* or gh-* (no hallucinated IDs)`);
else fail('Signal ID Format', `${badIds.length} hallucinated IDs detected: ${badIds.slice(0, 5).join(', ')}`);

// 10 — what_you_can_do not vague
const vagueKw = ['monitor', 'watch', 'stay informed', 'keep an eye', 'follow developments', 'track this', 'consider exploring'];
const vagueThemes = themes.filter(t => vagueKw.some(kw => (t.what_you_can_do || '').toLowerCase().includes(kw)));
if (vagueThemes.length === 0) pass('Actionability', 'No vague action language detected in any theme');
else fail('Actionability', `${vagueThemes.length} themes have vague what_you_can_do: ${vagueThemes.map(t => `"${t.title}"`).join(', ')}`);

// 11 — Brief word count
if (brief?.content) {
  const wc = brief.content.trim().split(/\s+/).length;
  if (wc <= 800) pass('Brief Word Count', `${wc} words (limit: 800)`);
  else fail('Brief Word Count', `${wc} words — exceeds 800 word limit by ${wc - 800}`);
} else {
  warn('Brief Exists', 'No weekly brief found in Supabase for this week');
}

// 12 — Brief required sections
if (brief?.content) {
  const required = ['Executive Summary', 'Key Themes', 'Watch List'];
  const missingSections = required.filter(s => !brief.content.includes(s));
  if (missingSections.length === 0) pass('Brief Sections', 'Has Executive Summary, Key Themes, Watch List');
  else fail('Brief Sections', `Missing sections: ${missingSections.join(', ')}`);
}

const passed = checks.filter(c => c.status === 'PASS').length;
const failed = checks.filter(c => c.status === 'FAIL').length;
const warned = checks.filter(c => c.status === 'WARN').length;
console.log(`Eval complete — ${passed}/${checks.length} passed | ${failed} failures | ${warned} warnings`);

return [{ json: {
  week_number, year, checks,
  summary: { score: `${passed}/${checks.length}`, passed, failed, warned, total: checks.length },
  run_stats: { avg_confidence: run.avg_confidence, total_signals: run.total_signals_processed, total_themes: run.total_themes, run_id: run.run_id }
} }];

const { checks, summary, week_number, year, run_stats } = $input.first().json;

const icon = s => ({ PASS: '✅', FAIL: '❌', WARN: '⚠️' }[s] || '?');
const verdict = summary.failed > 0 ? '🔴 NEEDS FIXES' : summary.warned > 0 ? '🟡 REVIEW WARNINGS' : '🟢 ALL CLEAR';

const lines = [
  `# CalmFalcon Pipeline Eval — Week ${week_number}/${year}`,
  `## ${verdict}  ·  Score: ${summary.score}  (${summary.passed} pass · ${summary.warned} warn · ${summary.failed} fail)`,
  ``,
  `**Pipeline:** ${run_stats.total_signals} signals → ${run_stats.total_themes} themes · avg confidence ${run_stats.avg_confidence}% · run \`${run_stats.run_id}\``,
  ``,
  `## Check Results`,
  ...checks.map(c => `${icon(c.status)} **${c.name}** — ${c.detail}`),
  ``,
  summary.failed > 0
    ? `## ❌ Action Required\nFix the ${summary.failed} failing check(s) before demo day.`
    : summary.warned > 0
    ? `## ⚠️ Review Before Demo\nNo blockers, but review ${summary.warned} warning(s).`
    : `## ✅ Pipeline Output Looks Good\nAll ${summary.total} checks passed. Ready for demo.`
];

const report = lines.join('\n');
console.log(report);
return [{ json: { report, verdict, checks, ...summary, week_number, year, run_id: run_stats.run_id } }];

const { report, verdict, score, passed, failed, warned, total, checks, week_number, year, run_id } = $input.first().json;

const url = $vars.SUPABASE_URL;
const key = $vars.SUPABASE_KEY;
if (!url || !key) throw new Error('Set SUPABASE_URL and SUPABASE_KEY as workflow variables');

const row = {
  eval_type: 'automated',
  week_number,
  year,
  run_id: run_id || null,
  score,
  passed,
  failed,
  warned,
  overall_verdict: verdict,
  report_markdown: report,
  checks_detail: checks || []
};

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: `${url}/rest/v1/eval_reports`,
  headers: {
    'apikey': key,
    'Authorization': `Bearer ${key}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },
  body: JSON.stringify([row])
});

console.log(`Eval report saved — Week ${week_number}/${year} | ${verdict}`);
return [{ json: { saved: true, verdict, score, week_number, year } }];
